import{_ as a,c as l,o as t,ag as i}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"Telegram 插件使用说明（Claude Code）","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-20-elegram-plugin-guide.zh-CN.md","filePath":"ai/2026-03/2026-03-20-elegram-plugin-guide.zh-CN.md","lastUpdated":1774063394000}'),s={name:"ai/2026-03/2026-03-20-elegram-plugin-guide.zh-CN.md"};function o(n,e,p,d,c,r){return t(),l("div",null,e[0]||(e[0]=[i(`<h1 id="telegram-插件使用说明-claude-code" tabindex="-1">Telegram 插件使用说明（Claude Code） <a class="header-anchor" href="#telegram-插件使用说明-claude-code" aria-label="Permalink to &quot;Telegram 插件使用说明（Claude Code）&quot;">​</a></h1><p>本文基于以下官方文档整理：</p><ul><li>README: <a href="https://github.com/anthropics/claude-plugins-official/blob/main/external_plugins/telegram/README.md" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-plugins-official/blob/main/external_plugins/telegram/README.md</a></li><li>ACCESS: <a href="https://github.com/anthropics/claude-plugins-official/blob/main/external_plugins/telegram/ACCESS.md" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-plugins-official/blob/main/external_plugins/telegram/ACCESS.md</a></li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这是一个给 <code>Claude Code</code> 使用的 Telegram 插件。它会启动一个 MCP Server，以 Telegram Bot 的身份登录，把你发给 Bot 的消息转发到当前 Claude Code 会话中。</p><p>接入后，你可以：</p><ul><li>在 Telegram 中直接给 Bot 发消息，由 Claude 处理并回复</li><li>让 Claude 给 Telegram 消息添加 reaction</li><li>让 Claude 编辑自己发出的消息，用于展示处理中状态或更新结果</li><li>发送图片或文件给 Claude，让 Claude 在本地读取</li></ul><p>这不是通用的 Telegram Bot SDK 教程，也不是独立 Web 服务部署文档。文中的命令如 <code>/plugin install</code>、<code>/telegram:configure</code>、<code>/telegram:access</code> 都是在 <code>Claude Code</code> 会话内执行的。</p><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul><li>你希望通过 Telegram 私聊 Claude</li><li>你希望把 Telegram 作为 Claude Code 的一个消息通道</li><li>你希望在群组里通过 @提及方式触发 Claude</li></ul><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><p>开始前请确认：</p><ul><li>已安装并可运行 <code>Claude Code</code></li><li>已安装 <code>Bun</code></li><li>可以正常访问 Telegram</li><li>拥有一个通过 <code>@BotFather</code> 创建的 Telegram Bot</li></ul><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>整体流程如下：</p><ol><li>你在 Telegram 中给 Bot 发消息</li><li>Telegram 插件接收消息并转给当前 Claude Code 会话</li><li>Claude 处理消息</li><li>插件再把 Claude 的回复发回 Telegram</li></ol><p>默认情况下，插件不会让任何陌生人直接接入当前会话。首次私聊 Bot 的用户会收到一个 6 位配对码，只有你在 Claude Code 中确认配对后，该用户后续消息才会真正进入会话。</p><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><h3 id="_1-创建-telegram-bot" tabindex="-1">1. 创建 Telegram Bot <a class="header-anchor" href="#_1-创建-telegram-bot" aria-label="Permalink to &quot;1. 创建 Telegram Bot&quot;">​</a></h3><p>在 Telegram 中打开 <code>@BotFather</code>，发送：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/newbot</span></span></code></pre></div><p>然后按提示完成两项设置：</p><ul><li><code>Name</code>：显示名称，可包含空格</li><li><code>Username</code>：唯一用户名，必须以 <code>bot</code> 结尾，例如 <code>my_assistant_bot</code></li></ul><p>创建完成后，<code>BotFather</code> 会返回一个 Token，格式类似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>123456789:AAHfiqksKZ8...</span></span></code></pre></div><p>请完整保存这个 Token。</p><h3 id="_2-在-claude-code-中安装插件" tabindex="-1">2. 在 Claude Code 中安装插件 <a class="header-anchor" href="#_2-在-claude-code-中安装插件" aria-label="Permalink to &quot;2. 在 Claude Code 中安装插件&quot;">​</a></h3><p>先启动一个 <code>claude</code> 会话，然后在会话中执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add anthropics/claude-code</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/plugin install telegram@claude-plugins-official</span></span>
<span class="line"><span>/reload-plugins</span></span></code></pre></div><p>执行后，可以尝试输入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:configure</span></span></code></pre></div><p>如果命令能够补全，说明插件已加载成功。若不能补全，按官方说明重启 Claude Code 会话再试。</p><h3 id="_3-配置-bot-token" tabindex="-1">3. 配置 Bot Token <a class="header-anchor" href="#_3-配置-bot-token" aria-label="Permalink to &quot;3. 配置 Bot Token&quot;">​</a></h3><p>在 Claude Code 会话中执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:configure 123456789:AAHfiqksKZ8...</span></span></code></pre></div><p>这会把 Token 写入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/channels/telegram/.env</span></span></code></pre></div><p>其中会包含：</p><div class="language-dotenv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dotenv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">TELEGRAM_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123456789:AAHfiqksKZ8...</span></span></code></pre></div><p>也可以手动写入这个文件，或者通过 shell 环境变量设置。官方文档说明：shell 环境变量优先级更高。</p><h3 id="_4-用-telegram-channel-参数重新启动-claude" tabindex="-1">4. 用 Telegram Channel 参数重新启动 Claude <a class="header-anchor" href="#_4-用-telegram-channel-参数重新启动-claude" aria-label="Permalink to &quot;4. 用 Telegram Channel 参数重新启动 Claude&quot;">​</a></h3><p>插件仅安装还不够。要让 Telegram 通道真正连接起来，你需要退出当前会话，并用以下命令重新启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin:telegram@claude-plugins-official</span></span></code></pre></div><p>如果不带这个参数，Telegram MCP Server 不会连接。</p><h3 id="_5-在-telegram-中与-bot-配对" tabindex="-1">5. 在 Telegram 中与 Bot 配对 <a class="header-anchor" href="#_5-在-telegram-中与-bot-配对" aria-label="Permalink to &quot;5. 在 Telegram 中与 Bot 配对&quot;">​</a></h3><p>现在去 Telegram 私聊你的 Bot。第一次发消息时，Bot 会回复一个 6 位配对码。</p><p>回到 Claude Code 会话中执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access pair &lt;6位配对码&gt;</span></span></code></pre></div><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access pair a4f91c</span></span></code></pre></div><p>完成后，该 Telegram 用户会被加入允许列表，之后再给 Bot 发消息，就会进入 Claude Code 会话。</p><h3 id="_6-修改默认访问策略" tabindex="-1">6. 修改默认访问策略 <a class="header-anchor" href="#_6-修改默认访问策略" aria-label="Permalink to &quot;6. 修改默认访问策略&quot;">​</a></h3><p>默认策略是 <code>pairing</code>。这意味着陌生人如果私聊你的 Bot，仍然可能收到配对码提示。</p><p>建议在你完成首次配对后，立即切换为仅允许白名单用户访问：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access policy allowlist</span></span></code></pre></div><p>这样未授权用户的私聊消息会被直接忽略，不再收到配对码。</p><h2 id="常用命令" tabindex="-1">常用命令 <a class="header-anchor" href="#常用命令" aria-label="Permalink to &quot;常用命令&quot;">​</a></h2><h3 id="插件安装与配置" tabindex="-1">插件安装与配置 <a class="header-anchor" href="#插件安装与配置" aria-label="Permalink to &quot;插件安装与配置&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install telegram@claude-plugins-official</span></span>
<span class="line"><span>/reload-plugins</span></span>
<span class="line"><span>/telegram:configure &lt;BOT_TOKEN&gt;</span></span></code></pre></div><h3 id="访问控制" tabindex="-1">访问控制 <a class="header-anchor" href="#访问控制" aria-label="Permalink to &quot;访问控制&quot;">​</a></h3><p>查看当前状态：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access</span></span></code></pre></div><p>批准一个配对码：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access pair &lt;code&gt;</span></span></code></pre></div><p>拒绝一个配对请求：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access deny &lt;code&gt;</span></span></code></pre></div><p>手动允许一个用户 ID：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access allow &lt;user_id&gt;</span></span></code></pre></div><p>移除一个用户 ID：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access remove &lt;user_id&gt;</span></span></code></pre></div><p>切换私聊策略：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access policy pairing</span></span>
<span class="line"><span>/telegram:access policy allowlist</span></span>
<span class="line"><span>/telegram:access policy disabled</span></span></code></pre></div><h2 id="访问控制说明" tabindex="-1">访问控制说明 <a class="header-anchor" href="#访问控制说明" aria-label="Permalink to &quot;访问控制说明&quot;">​</a></h2><p>Telegram Bot 是公开可寻址的。只要别人知道 Bot 用户名，就可以给它发私聊消息。因此访问控制非常重要。</p><p>官方文档中的核心策略如下：</p><ul><li><code>pairing</code><ul><li>默认值</li><li>未授权用户私聊 Bot 时，Bot 回复一个 6 位配对码</li><li>原消息不会直接进入 Claude</li></ul></li><li><code>allowlist</code><ul><li>仅白名单用户可访问</li><li>未授权用户的消息会被静默丢弃</li></ul></li><li><code>disabled</code><ul><li>完全禁用消息接入</li><li>即使是已授权用户也无法通过该通道访问</li></ul></li></ul><p>访问控制配置文件位于：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/channels/telegram/access.json</span></span></code></pre></div><p>如果该文件不存在，效果等同于：</p><ul><li><code>dmPolicy = pairing</code></li><li>没有任何已授权用户</li><li>没有启用任何群组</li></ul><h2 id="用户-id-与群组-id" tabindex="-1">用户 ID 与群组 ID <a class="header-anchor" href="#用户-id-与群组-id" aria-label="Permalink to &quot;用户 ID 与群组 ID&quot;">​</a></h2><p>访问控制存储的是 Telegram 的数字 ID，而不是用户名。</p><h3 id="用户-id" tabindex="-1">用户 ID <a class="header-anchor" href="#用户-id" aria-label="Permalink to &quot;用户 ID&quot;">​</a></h3><p>Telegram 用户名可变，数字 ID 才是稳定标识。</p><p>如果你要手动添加用户，可以让对方联系：</p><ul><li><code>@userinfobot</code></li></ul><p>它会返回用户的数字 ID。</p><h3 id="群组-id" tabindex="-1">群组 ID <a class="header-anchor" href="#群组-id" aria-label="Permalink to &quot;群组 ID&quot;">​</a></h3><p>Supergroup 的 ID 通常是负数，并带 <code>-100</code> 前缀，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-1001654782309</span></span></code></pre></div><p>Telegram 客户端界面通常不会直接显示群组 ID。官方建议通过以下方式获取：</p><ul><li>临时把 <code>@RawDataBot</code> 拉进群，读取其输出的 JSON</li><li>把你的 Bot 拉进群后，通过 <code>/telegram:access</code> 查看最近被丢弃的群消息信息</li></ul><h2 id="群组使用方法" tabindex="-1">群组使用方法 <a class="header-anchor" href="#群组使用方法" aria-label="Permalink to &quot;群组使用方法&quot;">​</a></h2><p>Telegram 插件默认只处理私聊，不处理群组。若要启用某个群组，需要手动添加群组 ID：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access group add -1001654782309</span></span></code></pre></div><p>移除群组：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access group rm -1001654782309</span></span></code></pre></div><h3 id="默认群组触发方式" tabindex="-1">默认群组触发方式 <a class="header-anchor" href="#默认群组触发方式" aria-label="Permalink to &quot;默认群组触发方式&quot;">​</a></h3><p>默认情况下，群组配置为 <code>requireMention: true</code>。这意味着只有以下情况会触发 Bot：</p><ul><li>明确 <code>@botusername</code></li><li>回复 Bot 发出的消息</li><li>匹配你配置的 <code>mentionPatterns</code></li></ul><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access set mentionPatterns &#39;[&quot;^hey claude\\\\b&quot;, &quot;\\\\bassistant\\\\b&quot;]&#39;</span></span></code></pre></div><h3 id="让-bot-处理群里的所有消息" tabindex="-1">让 Bot 处理群里的所有消息 <a class="header-anchor" href="#让-bot-处理群里的所有消息" aria-label="Permalink to &quot;让 Bot 处理群里的所有消息&quot;">​</a></h3><p>如果你希望 Bot 处理群里所有消息，可以这样配置：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access group add -1001654782309 --no-mention</span></span></code></pre></div><p>但这还不够。你还必须去 <code>@BotFather</code> 关闭该 Bot 的隐私模式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/setprivacy</span></span></code></pre></div><p>然后选择你的 Bot，并执行 <code>Disable</code>。</p><p>如果不关闭隐私模式，即使本地配置了 <code>--no-mention</code>，Telegram 服务器也不会把普通群消息投递给你的 Bot。</p><h2 id="插件暴露给-claude-的能力" tabindex="-1">插件暴露给 Claude 的能力 <a class="header-anchor" href="#插件暴露给-claude-的能力" aria-label="Permalink to &quot;插件暴露给 Claude 的能力&quot;">​</a></h2><p>根据 README，该插件会向 Claude 暴露以下工具能力：</p><h3 id="reply" tabindex="-1"><code>reply</code> <a class="header-anchor" href="#reply" aria-label="Permalink to &quot;\`reply\`&quot;">​</a></h3><p>用于给 Telegram 聊天发送消息。</p><p>支持：</p><ul><li><code>chat_id</code></li><li><code>text</code></li><li><code>reply_to</code></li><li><code>files</code></li></ul><p>特点：</p><ul><li>文本过长时会自动分段</li><li>图片文件会以照片方式发送并带预览</li><li>其他文件会作为文档发送</li><li>单个文件最大 50MB</li></ul><h3 id="react" tabindex="-1"><code>react</code> <a class="header-anchor" href="#react" aria-label="Permalink to &quot;\`react\`&quot;">​</a></h3><p>给某条消息添加 emoji reaction。</p><p>注意：Telegram 只接受固定白名单中的 reaction 表情，不在名单中的表情可能会静默失败。</p><h3 id="edit-message" tabindex="-1"><code>edit_message</code> <a class="header-anchor" href="#edit-message" aria-label="Permalink to &quot;\`edit_message\`&quot;">​</a></h3><p>编辑 Bot 自己之前发出的消息。</p><p>适合这类场景：</p><ul><li>先发送“处理中...”</li><li>完成后把原消息改成正式结果</li></ul><h2 id="图片与文件处理" tabindex="-1">图片与文件处理 <a class="header-anchor" href="#图片与文件处理" aria-label="Permalink to &quot;图片与文件处理&quot;">​</a></h2><p>README 说明：</p><ul><li>收到的图片会被下载到本地目录</li><li>本地路径会随频道通知一起提供给 Claude</li><li>Claude 可以进一步读取这个本地文件</li></ul><p>默认下载目录：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/channels/telegram/inbox/</span></span></code></pre></div><p>注意：</p><ul><li>Telegram 会压缩普通图片</li><li>如果你需要原始文件，应该在 Telegram 中以“文件”而不是“照片”的方式发送</li></ul><h2 id="消息长度与回复行为" tabindex="-1">消息长度与回复行为 <a class="header-anchor" href="#消息长度与回复行为" aria-label="Permalink to &quot;消息长度与回复行为&quot;">​</a></h2><p>Telegram 单条消息长度上限为 <code>4096</code> 字符。插件会自动分块发送。</p><p>可配置项包括：</p><ul><li><code>replyToMode</code><ul><li><code>first</code>：只有第一段回复挂在线程下</li><li><code>all</code>：所有分段都挂在线程下</li><li><code>off</code>：所有分段都独立发送</li></ul></li><li><code>textChunkLimit</code><ul><li>文本分段阈值</li></ul></li><li><code>chunkMode</code><ul><li><code>length</code>：按长度硬切</li><li><code>newline</code>：优先按换行或段落切分</li></ul></li></ul><p>示例：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access set ackReaction &quot;&quot;</span></span></code></pre></div><h2 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h2><p>这是官方文档里非常关键的一部分。</p><h3 id="_1-没有历史消息和搜索" tabindex="-1">1. 没有历史消息和搜索 <a class="header-anchor" href="#_1-没有历史消息和搜索" aria-label="Permalink to &quot;1. 没有历史消息和搜索&quot;">​</a></h3><p>Telegram Bot API 不提供历史消息读取或搜索能力，因此：</p><ul><li>插件只能看到新收到的消息</li><li>无法让 Claude 回头检索旧消息</li><li>不存在 <code>fetch_messages</code> 这类工具</li></ul><p>如果 Claude 需要更早的上下文，你只能手动把历史内容贴给它，或者自己做摘要。</p><h3 id="_2-无法事后下载历史附件" tabindex="-1">2. 无法事后下载历史附件 <a class="header-anchor" href="#_2-无法事后下载历史附件" aria-label="Permalink to &quot;2. 无法事后下载历史附件&quot;">​</a></h3><p>由于无法回溯历史消息，插件也无法在事后下载历史附件。图片之所以可用，是因为插件在消息到达时就立即下载了。</p><h3 id="_3-reaction-受-telegram-白名单限制" tabindex="-1">3. Reaction 受 Telegram 白名单限制 <a class="header-anchor" href="#_3-reaction-受-telegram-白名单限制" aria-label="Permalink to &quot;3. Reaction 受 Telegram 白名单限制&quot;">​</a></h3><p>不是所有 emoji 都可用，不在 Telegram Bot API 支持列表中的 reaction 可能不会报错，但也不会生效。</p><h2 id="推荐的安全配置" tabindex="-1">推荐的安全配置 <a class="header-anchor" href="#推荐的安全配置" aria-label="Permalink to &quot;推荐的安全配置&quot;">​</a></h2><p>如果你只是个人使用，推荐采用以下做法：</p><ol><li>创建专用私有 Bot，不要使用易猜的用户名</li><li>首次完成配对后，立即执行：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access policy allowlist</span></span></code></pre></div><ol start="3"><li>只把自己的 Telegram 账号加入允许列表</li><li>如果启用群组，尽量保留 <code>requireMention: true</code></li><li>不要把 Bot Token 提交到代码仓库</li></ol><h2 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h2><h3 id="telegram-configure-无法补全" tabindex="-1"><code>/telegram:configure</code> 无法补全 <a class="header-anchor" href="#telegram-configure-无法补全" aria-label="Permalink to &quot;\`/telegram:configure\` 无法补全&quot;">​</a></h3><p>可能原因：</p><ul><li>插件未正确安装</li><li><code>/reload-plugins</code> 后当前会话未刷新</li></ul><p>处理建议：</p><ul><li>重新执行安装命令</li><li>重新加载插件</li><li>直接重启 Claude Code 会话</li></ul><h3 id="bot-已创建-但-telegram-没有响应" tabindex="-1">Bot 已创建，但 Telegram 没有响应 <a class="header-anchor" href="#bot-已创建-但-telegram-没有响应" aria-label="Permalink to &quot;Bot 已创建，但 Telegram 没有响应&quot;">​</a></h3><p>优先检查：</p><ul><li>是否正确配置了 <code>TELEGRAM_BOT_TOKEN</code></li><li>是否使用了带 channel 参数的启动命令</li><li>是否当前会话确实通过以下方式启动：</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin:telegram@claude-plugins-official</span></span></code></pre></div><h3 id="收到配对码-但消息没有进入-claude" tabindex="-1">收到配对码，但消息没有进入 Claude <a class="header-anchor" href="#收到配对码-但消息没有进入-claude" aria-label="Permalink to &quot;收到配对码，但消息没有进入 Claude&quot;">​</a></h3><p>说明用户尚未完成授权。请在 Claude Code 中执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access pair &lt;code&gt;</span></span></code></pre></div><h3 id="群组里-了-bot-但它没有回应" tabindex="-1">群组里 @了 Bot，但它没有回应 <a class="header-anchor" href="#群组里-了-bot-但它没有回应" aria-label="Permalink to &quot;群组里 @了 Bot，但它没有回应&quot;">​</a></h3><p>优先检查：</p><ul><li>是否已执行 <code>group add</code></li><li>是否使用了正确的群组 ID</li><li>是否实际 @到了正确的 bot 用户名</li><li>如果使用了 <code>--no-mention</code>，是否已在 <code>@BotFather</code> 中关闭隐私模式</li></ul><h2 id="一套最小可用流程" tabindex="-1">一套最小可用流程 <a class="header-anchor" href="#一套最小可用流程" aria-label="Permalink to &quot;一套最小可用流程&quot;">​</a></h2><p>如果你只想最快跑通一次，可以按下面做：</p><ol><li>在 <code>@BotFather</code> 创建 Bot，拿到 Token</li><li>启动 <code>claude</code></li><li>在 Claude 会话中执行：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin install telegram@claude-plugins-official</span></span>
<span class="line"><span>/reload-plugins</span></span>
<span class="line"><span>/telegram:configure &lt;BOT_TOKEN&gt;</span></span></code></pre></div><ol start="4"><li>退出当前会话</li><li>用下面命令重新启动：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin:telegram@claude-plugins-official</span></span></code></pre></div><ol start="6"><li>在 Telegram 私聊 Bot，拿到配对码</li><li>回到 Claude 会话执行：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access pair &lt;code&gt;</span></span></code></pre></div><ol start="8"><li>再给 Bot 发消息，确认 Claude 可以正常回复</li><li>执行：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/telegram:access policy allowlist</span></span></code></pre></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>这个 Telegram 插件的核心价值是：让 <code>Claude Code</code> 能通过 Telegram Bot 对外收发消息。最常见的使用方式是个人私聊 Bot，通过配对机制把自己的 Telegram 账号绑定到当前 Claude 会话。</p><p>如果你把它理解成“给 Claude Code 增加一个 Telegram 消息入口”，理解就是对的；如果你把它理解成一个通用 Telegram Bot 开发框架，就不对了。</p>`,181)]))}const g=a(s,[["render",o]]);export{u as __pageData,g as default};
